const W4_ID = 'rMl9OJaA1hazqo1i';
const n8nHost = $env.N8N_HOST || 'https://vanguard-vanguard-n8n.0ul9nk.easypanel.host';
const apiKey = $env.N8N_API_KEY || '';
const hoje = new Date().toISOString().slice(0, 10);
let rodouHoje = false;
try {
  const url = n8nHost + '/api/v1/executions?workflowId=' + W4_ID + '&limit=5';
  const resp = await $http.get(url, { headers: { 'X-N8N-API-KEY': apiKey } });
  const execs = resp.data.data || [];
  rodouHoje = execs.some(function(e){ return e.startedAt && e.startedAt.startsWith(hoje) && e.status === 'success'; });
} catch(e) { rodouHoje = false; }
return [{ json: { rodouHoje: rodouHoje, hoje: hoje } }];

const agora = new Date();
const dataBR = agora.toLocaleDateString('pt-BR', {timeZone: 'America/Sao_Paulo'});
const horaBR = agora.toLocaleTimeString('pt-BR', {timeZone: 'America/Sao_Paulo', hour: '2-digit', minute: '2-digit'});
let content = '';
try {
  const raw = $input.item.json;
  if (raw && raw.content) {
    content = Buffer.from(raw.content.replace(/\n/g, ''), 'base64').toString('utf8');
  }
} catch(e) { content = ''; }
const linhas = content.split('\n');
const M = [], D = [];
for (var i = 0; i < linhas.length; i++) {
  var linha = linhas[i];
  if (!linha.match(/^\s*-\s*\[\s\]/)) continue;
  var tag = linha.indexOf('[musculo]') >= 0 ? 'musculo' : linha.indexOf('[diretor]') >= 0 ? 'diretor' : 'musculo';
  var texto = linha.replace(/^\s*-\s*\[\s\]\s*/, '').replace(/^\"?\d{4}-\d{2}-\d{2}\"?\s*/, '').replace(/\*\*/g, '').replace(/\[musculo\]|\[diretor\]/gi, '').trim().slice(0, 70);
  if (!texto) continue;
  if (tag === 'musculo') M.push(texto); else D.push(texto);
}
const total = M.length + D.length;
if (total === 0) return [];
let msg = 'Session Watch -- ' + dataBR + ' | ' + horaBR + '\n';
msg += 'session_close.ps1 nao executado ainda\n';
msg += '\nPendentes abertos: ' + total;
if (M.length > 0) {
  msg += '\n[musculo] ' + M.length + ':';
  M.slice(0, 3).forEach(function(i){ msg += '\n  * ' + i; });
  if (M.length > 3) msg += '\n  ... +' + (M.length - 3) + ' outros';
}
if (D.length > 0) {
  msg += '\n[diretor] ' + D.length + ':';
  D.slice(0, 3).forEach(function(i){ msg += '\n  * ' + i; });
  if (D.length > 3) msg += '\n  ... +' + (D.length - 3) + ' outros';
}
msg += '\n\nExecute: .\\scripts\\session_close.ps1';
return [{ json: { mensagem: msg, totalAbertos: total } }];
